1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	const CURSE_SURCHARGE = 0.5;
9	const FIRST_INSURANCE_SURCHARGE = 0.1;
10	const FOLLOW_UP_CONTRACT_DISCOUNT = 0.15;
11	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
12	const HIGH_ENCHANTMENT_THRESHOLD = 5;
13	const LOYALTY_DISCOUNT = 0.2;
14	const LOYALTY_YEARS_THRESHOLD = 2;
15	
16	export interface QuoteStep {
17	  op: "quote";
18	  items: Item[];
19	}
20	
21	export interface Damage {
22	  itemType: string;
23	  amount: number;
24	}
25	
26	export interface ClaimStep {
27	  op: "claim";
28	  policy: number;
29	  incident: {
30	    cause: string;
31	    damages: Damage[];
32	  };
33	}
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export interface Scenario {
38	  customer: { yearsWithMHPCO: number };
39	  steps: Step[];
40	}
41	
42	export interface QuoteResult {
43	  premium: number;
44	}
45	
46	export interface ClaimResult {
47	  payout: number;
48	  remainingCap: number;
49	}
50	
51	export type StepResult = QuoteResult | ClaimResult;
52	
53	export interface ScenarioResult {
54	  results: StepResult[];
55	}
56	
57	const PROCESSING_FEE = 5;
58	
59	const BASE_PREMIUM: Record<string, number> = {
60	  sword: 100,
61	  amulet: 60,
62	  staff: 80,
63	  potion: 40,
64	  rune: 25,
65	  moonstone: 25,
66	};
67	
68	const INSURANCE_VALUE: Record<string, number> = {
69	  sword: 1000,
70	  amulet: 600,
71	  staff: 800,
72	  potion: 400,
73	  rune: 250,
74	  moonstone: 250,
75	};
76	
77	const DEDUCTIBLE = 100;
78	const CAP_MULTIPLIER = 2;
79	
80	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
81	
82	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
83	const COMPONENT_BLOCK_SIZE = 3;
84	const COMPONENT_BLOCK_PRICE = 60;
85	
86	const groupByType = (items: Item[]): Map<string, Item[]> => {
87	  const groups = new Map<string, Item[]>();
88	  for (const item of items) {
89	    const group = groups.get(item.type) ?? [];
90	    group.push(item);
91	    groups.set(item.type, group);
92	  }
93	  return groups;
94	};
95	
96	const isHighlyEnchanted = (item: Item): boolean =>
97	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
98	
99	const itemSurchargeFactor = (item: Item): number =>
100	  (item.cursed ? CURSE_SURCHARGE : 0) +
101	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE : 0);
102	
103	const itemSurchargeAmount = (item: Item): number =>
104	  basePremiumFor(item) * itemSurchargeFactor(item);
105	
106	const groupBaseCost = (type: string, group: Item[]): number => {
107	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
108	    return COMPONENT_BLOCK_PRICE;
109	  }
110	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
111	};
112	
113	const policyBase = (items: Item[]): number =>
114	  Array.from(groupByType(items)).reduce(
115	    (sum, [type, group]) => sum + groupBaseCost(type, group),
116	    0,
117	  );
118	
119	const itemSurchargesTotal = (items: Item[]): number =>
120	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
121	
122	const policyModifierFactor = (
123	  customer: { yearsWithMHPCO: number },
124	  isFollowUp: boolean,
125	): number =>
126	  FIRST_INSURANCE_SURCHARGE -
127	  (customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? LOYALTY_DISCOUNT : 0) -
128	  (isFollowUp ? FOLLOW_UP_CONTRACT_DISCOUNT : 0);
129	
130	const validateItems = (items: Item[]): void => {
131	  for (const item of items) {
132	    if (!(item.type in BASE_PREMIUM)) {
133	      throw new Error(`Unknown item type: ${item.type}`);
134	    }
135	  }
136	};
137	
138	const quote = (
139	  items: Item[],
140	  customer: { yearsWithMHPCO: number },
141	  isFollowUp: boolean,
142	): QuoteResult => {
143	  validateItems(items);
144	  const base = policyBase(items);
145	  const itemSurcharges = itemSurchargesTotal(items);
146	  const policyModifiers = base * policyModifierFactor(customer, isFollowUp);
147	  return {
148	    premium: Math.ceil(base + itemSurcharges + policyModifiers + PROCESSING_FEE),
149	  };
150	};
151	
152	interface Policy {
153	  items: Item[];
154	  insuranceSum: number;
155	  remainingCap: number;
156	}
157	
158	const policyInsuranceSum = (items: Item[]): number =>
159	  items.reduce((sum, item) => sum + (INSURANCE_VALUE[item.type] ?? 0), 0);
160	
161	const createPolicy = (items: Item[]): Policy => {
162	  const insuranceSum = policyInsuranceSum(items);
163	  return {
164	    items,
165	    insuranceSum,
166	    remainingCap: insuranceSum * CAP_MULTIPLIER,
167	  };
168	};
169	
170	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
171	const HIGH_ENCHANTMENT_CLAIM_FACTOR = 0.5;
172	
173	const isHighlyEnchantedForClaim = (item: Item | undefined): boolean =>
174	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
175	
176	const reimbursableAmount = (item: Item | undefined, amount: number): number =>
177	  isHighlyEnchantedForClaim(item) ? amount * HIGH_ENCHANTMENT_CLAIM_FACTOR : amount;
178	
179	const damagePayout = (item: Item | undefined, amount: number): number =>
180	  Math.max(0, reimbursableAmount(item, amount) - DEDUCTIBLE);
181	
182	const findItemForDamage = (items: Item[], damage: Damage): Item | undefined =>
183	  items.find((item) => item.type === damage.itemType);
184	
185	const desiredPayout = (policy: Policy, damages: Damage[]): number =>
186	  damages.reduce(
187	    (sum, damage) =>
188	      sum + damagePayout(findItemForDamage(policy.items, damage), damage.amount),
189	    0,
190	  );
191	
192	const countByType = (xs: { type?: string; itemType?: string }[]): Map<string, number> => {
193	  const counts = new Map<string, number>();
194	  for (const x of xs) {
195	    const key = x.type ?? x.itemType ?? "";
196	    counts.set(key, (counts.get(key) ?? 0) + 1);
197	  }
198	  return counts;
199	};
200	
201	const validateDamages = (policy: Policy, damages: Damage[]): void => {
202	  const insuredCounts = countByType(policy.items);
203	  const damageCounts = countByType(damages);
204	  for (const damage of damages) {
205	    if (!insuredCounts.has(damage.itemType)) {
206	      throw new Error(`Damage references uninsured item: ${damage.itemType}`);
207	    }
208	    if (damage.amount < 0) {
209	      throw new Error(`Damage amount must be non-negative: ${damage.amount}`);
210	    }
211	  }
212	  for (const [type, count] of damageCounts) {
213	    if (count > (insuredCounts.get(type) ?? 0)) {
214	      throw new Error(`Too many damages for item type: ${type}`);
215	    }
216	  }
217	};
218	
219	const processClaim = (policy: Policy, step: ClaimStep): ClaimResult => {
220	  validateDamages(policy, step.incident.damages);
221	  const desired = desiredPayout(policy, step.incident.damages);
222	  const payout = Math.min(desired, policy.remainingCap);
223	  return { payout, remainingCap: policy.remainingCap - payout };
224	};
225	
226	interface ScenarioState {
227	  policies: Policy[];
228	  results: StepResult[];
229	}
230	
231	const applyStep = (
232	  state: ScenarioState,
233	  step: Step,
234	  customer: { yearsWithMHPCO: number },
235	): ScenarioState => {
236	  if (step.op === "quote") {
237	    const isFollowUp = state.policies.length > 0;
238	    return {
239	      policies: [...state.policies, createPolicy(step.items)],
240	      results: [...state.results, quote(step.items, customer, isFollowUp)],
241	    };
242	  }
243	  const claimResult = processClaim(state.policies[step.policy], step);
244	  const updatedPolicy: Policy = {
245	    ...state.policies[step.policy],
246	    remainingCap: claimResult.remainingCap,
247	  };
248	  return {
249	    policies: state.policies.map((p, i) =>
250	      i === step.policy ? updatedPolicy : p,
251	    ),
252	    results: [...state.results, claimResult],
253	  };
254	};
255	
256	export const runScenario = (scenario: Scenario): ScenarioResult => {
257	  const finalState = scenario.steps.reduce<ScenarioState>(
258	    (state, step) => applyStep(state, step, scenario.customer),
259	    { policies: [], results: [] },
260	  );
261	  return { results: finalState.results };
262	};
